import logging
import logging.handlers
import os
import stat
from pathlib import Path

def setup_secure_logging(log_dir="/var/log/myapp", log_file="app.log"):
    """Setup secure logging with rotation and proper permissions"""
    
    # Create log directory with secure permissions
    Path(log_dir).mkdir(parents=True, exist_ok=True)
    os.chmod(log_dir, stat.S_IRWXU | stat.S_IRGRP | stat.S_IXGRP | stat.S_IROTH | stat.S_IXOTH)
    
    # Full path to log file
    log_path = os.path.join(log_dir, log_file)
    
    # Create logger
    logger = logging.getLogger("secure_app")
    logger.setLevel(logging.DEBUG)
    
    # Prevent adding handlers multiple times
    if not logger.handlers:
        # Create file handler with rotation
        file_handler = logging.handlers.RotatingFileHandler(
            log_path,
            maxBytes=10485760,  # 10MB
            backupCount=5,
            encoding='utf-8'
        )
        
        # Set secure permissions on log file
        os.chmod(log_path, stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IWGRP)
        
        # Create formatter
        formatter = logging.Formatter(
            '%(asctime)s - %(name)s - %(levelname)s - %(message)s',
            datefmt='%Y-%m-%d %H:%M:%S'
        )
        
        file_handler.setFormatter(formatter)
        file_handler.setLevel(logging.DEBUG)
        
        logger.addHandler(file_handler)
    
    return logger

